import os

# Check if there's a GitHub token in the env file
env_path = os.path.expanduser('~/.hermes/.env')
github_token = None
if os.path.exists(env_path):
    with open(env_path) as f:
        for line in f:
            if line.startswith('GITHUB_TOKEN='):
                github_token = line.split('=', 1)[1].strip().strip('"\'')
                break

print(f"GITHUB_TOKEN in .env: {'✅ Found' if github_token else '❌ Not found'}")

# Also check auth.json
auth_path = os.path.expanduser('~/.hermes/auth.json')
if os.path.exists(auth_path):
    with open(auth_path) as f:
        auth_data = json.load(f)
    for provider, configs in auth_data.items():
        for c in configs:
            if 'api_key' in c and c.get('api_key'):
                print(f"  Provider '{provider}': has API key (masked)")

# Check git config
import subprocess
try:
    result = subprocess.run(['git', 'config', '--global', '-l'], capture_output=True, text=True)
    print(f"\nGlobal git config:\n{result.stdout[:500] if result.stdout else '(empty)'}")
except:
    pass
